/// Byte-exact comparison of Rust encoder output against C libopus FIXED_POINT reference.
/// Reference hex generated by encoding a 440Hz sine wave with the C encoder
/// built from /tmp/opus-fix-src with --enable-fixed-point.
/// Each config encodes 20 frames of 20ms (fs/50 samples per frame).

fn gen_pcm(fs: i32, num_samples: usize) -> Vec<f32> {
    // Use integer phase reduction to keep the sin() argument in [0, 2π],
    // avoiding precision loss at large arguments that causes platform-specific
    // i16 rounding differences (e.g. ARM NEON vs x86).
    // f64 sin in [0, 2π] is consistent across all IEEE-754 platforms.
    (0..num_samples)
        .map(|i| {
            let cycle = (440i64 * i as i64) % fs as i64;
            let phase = cycle as f64 / fs as f64;
            let s = (f64::sin(2.0 * std::f64::consts::PI * phase) * 16384.0) as i16;
            s as f32 / 32768.0
        })
        .collect()
}

fn run_config(fs: i32, bitrate: i32, complexity: i32, c_ref_hex: &[&str], label: &str) {
    use opus_rs::{Application, OpusEncoder};
    let frame_size = fs as usize / 50;
    let total_samples = frame_size * c_ref_hex.len();
    let pcm = gen_pcm(fs, total_samples);

    let mut encoder = OpusEncoder::new(fs, 1, Application::Voip).expect("encoder");
    encoder.complexity = complexity;
    encoder.bitrate_bps = bitrate;
    encoder.use_cbr = true;

    let mut mismatches = 0;
    for (i, ref_hex) in c_ref_hex.iter().enumerate() {
        let c_ref = hex_decode(ref_hex);
        let offset = i * frame_size;
        let mut out = vec![0u8; 1275];
        let n = encoder
            .encode(&pcm[offset..offset + frame_size], frame_size, &mut out)
            .unwrap();
        let pkt = &out[..n];
        if pkt != c_ref.as_slice() {
            mismatches += 1;
            let rust_hex: String = pkt.iter().map(|b| format!("{:02x}", b)).collect();
            println!("[{}] Frame {}: MISMATCH", label, i);
            println!("  C:    {}", ref_hex);
            println!("  Rust: {}", rust_hex);
            for j in 0..pkt.len().min(c_ref.len()) {
                if pkt[j] != c_ref[j] {
                    println!(
                        "  First diff byte {}: C=0x{:02x} Rust=0x{:02x}",
                        j, c_ref[j], pkt[j]
                    );
                    break;
                }
            }
        }
    }
    println!(
        "[{}] {}/{} frames match",
        label,
        c_ref_hex.len() - mismatches,
        c_ref_hex.len()
    );
    assert_eq!(mismatches, 0, "{}: {} frames mismatched", label, mismatches);
}

fn hex_decode(s: &str) -> Vec<u8> {
    (0..s.len())
        .step_by(2)
        .map(|i| u8::from_str_radix(&s[i..i + 2], 16).unwrap())
        .collect()
}

